class VectorStore:
    def __init__(self, db_path: str):
        self.db_path = db_path
        self.conn = sqlite3.connect(self.db_path, check_same_thread=False)
        self.conn.execute("PRAGMA journal_mode=WAL;")
        self._create_tables()

    def _create_tables(self):
        self.conn.execute("""
            CREATE TABLE IF NOT EXISTS documents (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                source TEXT NOT NULL,
                chunk_index INTEGER NOT NULL,
                content TEXT NOT NULL,
                metadata TEXT,
                content_hash TEXT UNIQUE NOT NULL
            )
        """)
        self.conn.execute("""
            CREATE TABLE IF NOT EXISTS embeddings (
                document_id INTEGER PRIMARY KEY,
                vector BLOB NOT NULL,
                dimension INTEGER NOT NULL,
                FOREIGN KEY(document_id) REFERENCES documents(id) ON DELETE CASCADE
            )
        """)
        self.conn.commit()

    def upsert_document_chunk(
        self,
        source: str,
        chunk_index: int,
        content: str,
        metadata: Dict[str, Any],
        embedding: np.ndarray
    ):
        content_hash = hashlib.sha256(f"{source}:{chunk_index}:{content}".encode("utf-8")).hexdigest()
        cur = self.conn.cursor()
        cur.execute("SELECT id FROM documents WHERE content_hash = ?", (content_hash,))
        row = cur.fetchone()
        if row:
            doc_id = row[0]
            cur.execute(
                "UPDATE documents SET source = ?, chunk_index = ?, content = ?, metadata = ? WHERE id = ?",
                (source, chunk_index, content, json.dumps(metadata), doc_id)
            )
            cur.execute(
                "REPLACE INTO embeddings (document_id, vector, dimension) VALUES (?, ?, ?)",
                (doc_id, embedding.astype(np.float32).tobytes(), int(embedding.shape[0]))
            )
        else:
            cur.execute(
                "INSERT INTO documents (source, chunk_index, content, metadata, content_hash) VALUES (?, ?, ?, ?, ?)",
                (source, chunk_index, content, json.dumps(metadata), content_hash)
            )
            doc_id = cur.lastrowid
            cur.execute(
                "INSERT OR REPLACE INTO embeddings (document_id, vector, dimension) VALUES (?, ?, ?)",
                (doc_id, embedding.astype(np.float32).tobytes(), int(embedding.shape[0]))
            )
        self.conn.commit()

    def get_all_embeddings(self) -> List[Dict[str, Any]]:
        cur = self.conn.cursor()
        cur.execute("""
            SELECT d.id, d.source, d.chunk_index, d.content, d.metadata, e.vector, e.dimension
            FROM documents d
            JOIN embeddings e ON d.id = e.document_id
        """)
        rows = cur.fetchall()
        results = []
        for row in rows:
            doc_id, source, chunk_index, content, metadata, vector_blob, dimension = row
            vector = np.frombuffer(vector_blob, dtype=np.float32)
            if vector.shape[0] != dimension:
                continue
            results.append({
                "id": doc_id,
                "source": source,
                "chunk_index": chunk_index,
                "content": content,
                "metadata": json.loads(metadata) if metadata else {},
                "embedding": vector
            })
        return results

    def similarity_search(self, query_embedding: np.ndarray, top_k: int = 5) -> List[Dict[str, Any]]:
        docs = self.get_all_embeddings()
        if not docs:
            return []

        q = query_embedding.astype(np.float32)
        q_norm = np.linalg.norm(q)
        if q_norm == 0:
            return []

        scored = []
        for doc in docs:
            v = doc["embedding"]
            denom = (np.linalg.norm(v) * q_norm)
            score = float(np.dot(q, v) / denom) if denom != 0 else 0.0
            scored.append((score, doc))

        scored.sort(key=lambda x: x[0], reverse=True)
        results = []
        for score, doc in scored[:top_k]:
            results.append({
                "id": doc["id"],
                "source": doc["source"],
                "chunk_index": doc["chunk_index"],
                "content": doc["content"],
                "metadata": doc["metadata"],
                "score": score
            })
        return results


class Embedder:
    def __init__(self, model_name: str):
        self.model = SentenceTransformer(model_name)

    def embed_texts(self, texts: List[str]) -> np.ndarray:
        embeddings = self.model.encode(texts, convert_to_numpy=True, normalize_embeddings=False)
        return embeddings.astype(np.float32)

    def embed_query(self, text: str) -> np.ndarray:
        embedding = self.model.encode([text], convert_to_numpy=True, normalize_embeddings=False)[0]
        return embedding.astype(np.float32)


class DocumentLoader:
    SUPPORTED_EXTENSIONS = {".txt", ".md", ".markdown", ".json"}

    @staticmethod
    def load_documents(directory: str) -> List[Dict[str, Any]]:
        docs = []
        base = Path(directory)
        if not base.exists():
            return docs

        for path in base.rglob("*"):
            if not path.is_file():
                continue
            if path.suffix.lower() not in DocumentLoader.SUPPORTED_EXTENSIONS:
                continue

            try:
                text = DocumentLoader._read_file(path)
                if text.strip():
                    docs.append({
                        "source": str(path),
                        "content": text,
                        "metadata": {
                            "filename": path.name,
                            "extension": path.suffix.lower()
                        }
                    })
            except Exception:
                continue
        return docs

    @staticmethod
    def _read_file(path: Path) -> str:
        if path.suffix.lower() == ".json":
            with open(path, "r", encoding="utf-8") as f:
                data = json.load(f)
            return json.dumps(data, ensure_ascii=False, indent=2)
        with open(path, "r", encoding="utf-8") as f:
            return f.read()


def chunk_text(text: str, chunk_size: int = 1000, overlap: int = 150) -> List[str]:
    text = " ".join(text.split())
    if len(text) <= chunk_size:
        return [text]

    chunks = []
    start = 0
    while start < len(text):
        end = start + chunk_size
        chunk = text[start:end]
        chunks.append(chunk)
        if end >= len(text):
            break
        start = max(end - overlap, start + 1)
    return chunks


class RAGSystem:
    def __init__(
        self,
        db_path: str,
        docs_dir: str,
        embed_model_name: str,
        openai_api_key: str,
        llm_model: str
    ):
        self.vector_store = VectorStore(db_path)
        self.embedder = Embedder(embed_model_name)
        self.docs_dir = docs_dir
        self.llm_model = llm_model
        self.client = OpenAI(api_key=openai_api_key) if openai_api_key else None

    def index_documents(self):
        documents = DocumentLoader.load_documents(self.docs_dir)
        for doc in documents:
            chunks = chunk_text(doc["content"], CHUNK_SIZE, CHUNK_OVERLAP)
            embeddings = self.embedder.embed_texts(chunks)
            for i, (chunk, embedding) in enumerate(zip(chunks, embeddings)):
                metadata = dict(doc["metadata"])
                metadata["source"] = doc["source"]
                metadata["chunk_index"] = i
                self.vector_store.upsert_document_chunk(
                    source=doc["source"],
                    chunk_index=i,
                    content=chunk,
                    metadata=metadata,
                    embedding=embedding
                )

    def retrieve(self, query: str, top_k: int = TOP_K) -> List[Dict[str, Any]]:
        query_embedding = self.embedder.embed_query(query)
        return self.vector_store.similarity_search(query_embedding, top_k=top_k)

    def build_prompt(self, query: str, retrieved_docs: List[Dict[str, Any]]) -> str:
        context_sections = []
        for i, doc in enumerate(retrieved_docs, start=1):
            context_sections.append(
                f"[Document {i}]\n"
                f"Source: {doc['source']}\n"
                f"Chunk: {doc['chunk_index']}\n"
                f"Relevance Score: {doc['score']:.4f}\n"
                f"Content:\n{doc['content']}\n"
            )

        context = "\n".join(context_sections) if context_sections else "No relevant documents found."

        prompt = (
            "You are an internal company knowledge base assistant. "
            "Answer the user's question using only the provided retrieved documents. "
            "If the answer is not present in the documents, say you do not know based on the available internal knowledge.\n\n"
            f"Retrieved Documents:\n{context}\n\n"
            f"User Question:\n{query}\n\n"
            "Answer:"
        )
        return prompt

    def generate_answer(self, query: str, top_k: int = TOP_K) -> Dict[str, Any]:
        retrieved_docs = self.retrieve(query, top_k=top_k)
        prompt = self.build_prompt(query, retrieved_docs)

        if not self.client:
            return {
                "query": query,
                "answer": "OPENAI_API_KEY is not configured.",
                "retrieved_documents": retrieved_docs,
                "prompt": prompt
            }

        response = self.client.responses.create(
            model=self.llm_model,
            input=prompt
        )

        answer = getattr(response, "output_text", None)
        if not answer:
            try:
                answer = response.output[0].content[0].text
            except Exception:
                answer = "No response generated."

        return {
            "query": query,
            "answer": answer,
            "retrieved_documents": retrieved_docs,
            "prompt": prompt
        }


